import java.util.*;
import java.io.*;

public class Main {
    static long[] solveCase(int n, long[] seats) {
        // your code here — return the rearranged array
        return seats;
    }

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StreamTokenizer in = new StreamTokenizer(br);
        in.nextToken();
        int t = (int) in.nval;
        StringBuilder out = new StringBuilder();
        while (t-- > 0) {
            in.nextToken();
            int n = (int) in.nval;
            long[] seats = new long[n];
            for (int i = 0; i < n; i++) {
                in.nextToken();
                seats[i] = (long) in.nval;
            }
            long[] ans = solveCase(n, seats);
            for (int i = 0; i < n; i++) {
                out.append(ans[i]);
                out.append(i == n - 1 ? '\n' : ' ');
            }
        }
        System.out.print(out);
    }
}

